external_knowledge:
- Highly satisfying: specialty satisfaction level > 0.8;
- Low burnout: percentage of physicians feeling burned out < 0.2;
- Generous vacation time: average number of vacation days per year > 10.

sql:
SELECT AVG(income_satisfaction) AS AverageIncomeSatisfaction
FROM satisfaction_levels
WHERE specialty_id = 1 AND income_satisfaction < 0.5;

external_knowledge:
- "float higher than the ocean's tide" refers to specialties with an average salary above the overall average salary;
- "hidden depths through the prism of financial reward" refers to the average salary of the physicians;
- "seeking solace" refers to the percentage of physicians seeking help;
- "professional satisfaction" refers to the average satisfaction level with medicine as a career choice.

sql:
SELECT total_work_hours, average_vacation_days
FROM work_life_balance
WHERE specialty_id = 0;

SELECT num_physicians
FROM physician_stats
WHERE specialty_id = 1;

external_knowledge:
- "areas of study" refers to medical specialties;
- "a couple of years" means more than 2 years;
- "practitioners" refers to physicians;
- "typical training period" refers to residency_duration.

sql:
SELECT s.specialty_name, d.men, d.women 
FROM specialties s 
INNER JOIN demographics d ON s.specialty_id = d.specialty_id;

SELECT COUNT(specialty_id)
FROM physician_stats
WHERE num_physicians > 1000;

SELECT specialty_name
FROM specialties
WHERE specialty_id = 1;

SELECT AVG(s.medicine_satisfaction)
FROM satisfaction_levels s
WHERE s.medicine_satisfaction > (SELECT AVG(medicine_satisfaction) FROM satisfaction_levels);
